        if not self:IsTrackRecorded(LSdkMadFunTrack.AF_GUDIE_BEGIN) then
            self:RecordedTrack(LSdkMadFunTrack.AF_GUDIE_BEGIN)
            gLSdkImpl:CallMethod(LSdkMethod.StartNewRoleTutorial)

            if LOG_INFO_ENABLED then
                printInfoN("trackEvent", "StartNewRoleTutorial")
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_JOIN_GUILD, function()
        local guildInfo = gModelGuild and gModelGuild:GetSelfGuildInfo() or nil
