        if guildInfo.position == 1 then
            self:SendTrackEvent(LSdkMadFunTrack.AF_ALLIANCE_CREATE)
        else
            self:SendTrackEvent(LSdkMadFunTrack.AF_ALLIANCE_JOIN)
        end
    end)

