function LSdkMadFunTrack:IsTrackRecorded(afName)
    local ids = gModelPlayer and gModelPlayer:GetFireOneTimeEventIds() or {}
    local id = LSdkMadFunTrack.AF_IDS[afName]
    if not id then return true end
    if ids[id] then
        return true
    else
        return false
    end
end

function LSdkMadFunTrack:RecordedTrack(afName)
    if not gModelPlayer then return end
    local id = LSdkMadFunTrack.AF_IDS[afName]
    if not id then return end
    gModelPlayer:OnFireOnetimeEventReq(id)
end

function LSdkMadFunTrack:OnCallHeroReward(callNum, callRefId, itemList, fixedReward)
    local nameList = {
        [1001] = "nvshen",
        [1002] = "nvshen",
        [1003] = "nvshen",
        [1004] = "nvshen",
        [2001] = "yuwang",
        [2002] = "yuwang",
        [2003] = "yuwang",
        [2004] = "yuwang",
    }
    local name = nameList[callRefId]
    if string.isempty(name) then return end

    local heroIds = {}
    local itemIds = {}
    for k,v in ipairs(itemList or {}) do
        if v.itype == 2 then
            table.insert(heroIds, v.itemId)
        elseif v.itype == 1 then
            table.insert(itemIds, v.itemId)
        end
    end
    if fixedReward then
        if fixedReward.itemType == 2 then
            table.insert(heroIds, fixedReward.itemId)
        elseif fixedReward.itemType == 1 then
            table.insert(itemIds, fixedReward.itemId)
        end
    end
    self:_OnSendAfRecruit(callNum, name, heroIds, itemIds)
end

function LSdkMadFunTrack:OnCallMagicWheelReward(callNum, itemDetail)
    local heroIds = {}
    local itemIds = {}
    local runeIds = {}
    local equipIds = {}
    for i, v in ipairs(itemDetail) do
        local items = v.items or {}
        local heroes = v.heroes or {}
        local equips = v.equips or {}
        local runes = v.runes or {}
        for idx, val in ipairs(items) do
            table.insert(itemIds, val.refId)
        end
        for idx, val in ipairs(heroes) do
            table.insert(heroIds, val.refId)
        end
        for idx, val in ipairs(equips) do
            table.insert(equipIds, val.refId)
        end
        for idx, val in ipairs(runes) do
            table.insert(runeIds, val.refId)
        end
    end
    self:_OnSendAfRecruit(callNum, "riyuequan", heroIds, itemIds, runeIds, equipIds)
end

function LSdkMadFunTrack:_OnSendAfRecruit(callNum, name, heroIds, itemIds,runeIds, equipIds)
    --玩家抽卡的卡池名，nvshen 或者yuwang或者riyuequan

    local afName
    if callNum == 1 then
        afName = LSdkMadFunTrack.AF_RECRUIT_1
    else
        if not self:IsTrackRecorded(LSdkMadFunTrack.AF_FIRSTRECRUIT_10) then
            afName = LSdkMadFunTrack.AF_FIRSTRECRUIT_10
            self:RecordedTrack(afName)
        else
            afName = LSdkMadFunTrack.AF_RECRUIT_10
        end
    end
    local sHeroId = table.concat(heroIds, ",")
    local sItemId = table.concat(itemIds, ",")
    local sRuneId = runeIds and table.concat(runeIds, ",") or ""
    local sEquipId = equipIds and table.concat(equipIds, ",") or ""
    self:SendTrackEvent(afName, "af_banner_name", name, "af_getplayerids", sHeroId, "af_getitemids", sItemId,"af_getruneids", sRuneId, "af_getequipids", sEquipId)
end


function LSdkMadFunTrack:OnMainBattleFinished(battleNode)
    if not battleNode then return end
    if battleNode == 20010 then
        if not self:IsTrackRecorded(LSdkMadFunTrack.AF_GUDIE_END) then
            self:RecordedTrack(LSdkMadFunTrack.AF_GUDIE_END)
            gLSdkImpl:CallMethod(LSdkMethod.FinishNewRoleTutorial)
            if LOG_INFO_ENABLED then
                printInfoN("trackEvent", "FinishNewRoleTutorial")
            end
        end
    end
    local ref = GameTable.MainInstanceMissionRef[battleNode]
    if not ref then return end
    local chapterId = ref.belongChapterId
    local nextId = ref.NextinstanceId
    local sortIndex = ref.sort
    self:SendTrackEvent(LSdkMadFunTrack.AF_GUANQIA_FINISH, "af_chapter", chapterId, "af_guanqia", sortIndex)
    if nextId == -1 then
        self:SendTrackEvent(LSdkMadFunTrack.AF_CHAPTER_FINISH, "af_chapter", chapterId)
    end
end

function LSdkMadFunTrack:OnQuestDailyChange(outFinishedList)
    local taskType = ModelQuest.DAILY
    local isCheck = false
    for k,refId in ipairs(outFinishedList) do
        local cfg = GameTable.MissionRef[refId]
        if cfg and cfg.type == taskType then
            isCheck = true
            break
        end
    end
    if not isCheck then return end
    local finishState = ModelQuest.TASK_UNFINISH
    local questDataList = gModelQuest:GetQuestDataList()
    for k,v in pairs(questDataList) do
        if v:GetType() == taskType and v:GetState() == finishState then
            return
        end
    end
    self:SendTrackEvent(LSdkMadFunTrack.AF_DAILYTASKEND)
end

function LSdkMadFunTrack:OnPlayerVipLevelChange(oldVipLevel, newVipLevel)
    local afName = LSdkMadFunTrack.AF_LEICHONGVIP1
    if self:IsTrackRecorded(afName) then return end
    if oldVipLevel < 1 and newVipLevel >= 1 then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName)
    end
end

function LSdkMadFunTrack:OnGardenPlay()
    local afName = LSdkMadFunTrack.AF_GARDEN_HUDONG
    if self:IsTrackRecorded(afName) then return end
    self:RecordedTrack(afName)
    self:SendTrackEvent(afName)
end

function LSdkMadFunTrack:OnEndlessBattle()
    local afName = LSdkMadFunTrack.AF_ZHIXIAN_WUMAYOUHUO
    if self:IsTrackRecorded(afName) then return end
    self:RecordedTrack(afName)
    self:SendTrackEvent(afName)
end

function LSdkMadFunTrack:OnAlienInvasionBoss()
    local afName = LSdkMadFunTrack.AF_ZHIXIAN_JIAYULONGNU
    if self:IsTrackRecorded(afName) then return end
    if not gModelInvasion then return end
    local bossData = gModelInvasion:GetBossData()
    if not bossData then return end
    local maxCnt = gModelInvasion:GetInvasionPara("bossMaxNum") or 0
    local alreadyDareCount = bossData.alreadyDareCount or 0
    if alreadyDareCount < maxCnt then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName)
    end
end

function LSdkMadFunTrack:OnTowerFloorChange(layer)
    local afName = LSdkMadFunTrack.AF_ZHIXIAN_SHAONVMISHI
    if self:IsTrackRecorded(afName) then return end
    if layer == 1 then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName)
    end
end

function LSdkMadFunTrack:OnBattleFinished(combatType, winner)
    if combatType == LCombatTypeConst.COMBAT_DUNGEON_DAILY then
        if winner == 1 then
            local afName = LSdkMadFunTrack.AF_ZHIXIAN_SHAONVSHENJI
            if self:IsTrackRecorded(afName) then return end
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end
end

function LSdkMadFunTrack:OnBadgeGameUpdate()
    local afName = LSdkMadFunTrack.AF_ZHIXIAN_GONGLUEFANGXIN
    if self:IsTrackRecorded(afName) then return end
    local chapterId = gModelBadgeGame.chapterId
    local barrierId = gModelBadgeGame.barrierId
    if chapterId > 1 or barrierId >= 1 then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName)
    end
end

function LSdkMadFunTrack:OnActivityPageChange(modelId, sid, pageList)
    if modelId ~= ModelActivity.NEW_EIGHT_LOGIN then return end
    if not pageList then return end
    ---@type StructActivityPage
    local page = pageList[1]
    if not page then return end
    page = gModelActivity:GenerateActivePageDataFromPb(page)
    local entryMap = page.entryMap
    if not entryMap then return end
    local afName = LSdkMadFunTrack.AF_CIRIQIANDAO
    if not self:IsTrackRecorded(afName) then
        local entry = entryMap[2]
        if entry and entry.goalData and entry.goalData.status ==2 then
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end
    afName = LSdkMadFunTrack.AF_SANRIQIANDAO
    if not self:IsTrackRecorded(afName) then
        local entry = entryMap[3]
        if entry and entry.goalData and entry.goalData.status ==2 then
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end

    afName = LSdkMadFunTrack.AF_QIRIQIANDAO
    if not self:IsTrackRecorded(afName) then
        local entry = entryMap[7]
        if entry and entry.goalData and entry.goalData.status ==2 then
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end
end

function LSdkMadFunTrack:OnPrivilegeBuyIds(buyIds)
    local afName
    if buyIds[1] then
        afName = LSdkMadFunTrack.AF_TANSUOTEQUAN_BUY
        if not self:IsTrackRecorded(afName) then
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end
    if buyIds[3] then
        afName = LSdkMadFunTrack.AF_ZHONGSHENTEQUAN_BUY
        if not self:IsTrackRecorded(afName) then
            self:RecordedTrack(afName)
            self:SendTrackEvent(afName)
        end
    end

    if buyIds[2] or buyIds[4] or buyIds[6] then
        local nameList = {
            [2] = "shengji",
            [4] = "dujiaoshou",
            [6] = "longwen",
        }
        afName = LSdkMadFunTrack.AF_MONTHLYCARD_BUY
        --月订阅礼包名称：dujiaoshou或者shengji或者longwen
        for k,paramName in pairs(nameList) do
            if buyIds[k] then
                self:SendTrackEvent(afName, "af_monthlycardname", paramName)
            end
        end
    end

    if buyIds[5] then
        afName = LSdkMadFunTrack.AF_WEEKLYCARD_BUY
        self:SendTrackEvent(afName, "af_weeklycardname", "yuwang")
    end
end

