function LSdkMadFunTrack:RegSensorsEvent()
    local eventReg = self._behaviour
    eventReg:AddEventHandler(EventNames.SDK_INIT_OK, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500760)
    end)
    eventReg:AddEventHandler(EventNames.UPDATE_EXTRACT_RES_OK, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 502074, "result", "success")
    end)
    eventReg:AddEventHandler(EventNames.UPDATE_EXTRACT_RES_FAILURE, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 502074, "result", "failure")
    end)
    eventReg:AddEventHandler(EventNames.LOGIN_UPDATE_REQ_OK, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500780)
    end)
    eventReg:AddEventHandler(EventNames.LOGIN_UPDATE_REQ_FAILURE, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500762)
    end)
    eventReg:AddEventHandler(EventNames.UPDATE_NEED_INSTALL, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 501860, "is_update", 1)
    end)
    eventReg:AddEventHandler(EventNames.UPDATE_NO_INSTALL, function()
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 501860, "is_update", 0)
    end)
    eventReg:AddEventHandler(EventNames.OPEN_UPDATE_INSTALL, function(...)
        self:ForceUpdateApp(...)
    end)
    eventReg:AddEventHandler(EventNames.QUERY_REMOTE_FIlE_RESULT, function(isOk)
        self:GetDataJsonResult(isOk)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_NEED_HOT_RES, function(...)
        self:NeedUpdate(...)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_BEGIN_HOT_RES, function(...)
        self:BeginUpdate(...)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_HOT_RES_FAILURE, function(...)
        self:UpdateFailure(...)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_PROGRESS_HOT_RES, function(...)
        self:UpdateRecord(...)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_HOT_RES_FINISHED, function(...)
        self:FinishedUpdate(...)
    end)
end

function LSdkMadFunTrack:ForceUpdateApp(appUrl)
    if string.isempty(appUrl) then
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 501862)
    else
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 501862, "AppUrl", appUrl)
    end
end

function LSdkMadFunTrack:GetDataJsonResult(isOk)
    if isOk then
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500286)
    else
        gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500287)
    end
end

function LSdkMadFunTrack:NeedUpdate(totalSize, isAuto)
    gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500272, "totalSize", totalSize, "autoDownload", isAuto and "true" or "false")
end

function LSdkMadFunTrack:BeginUpdate(totalSize, isAuto)
    self._beginUpdateTime = Time.RawUnityEngineTime.realtimeSinceStartup
    self._updateTotalSize = totalSize
    gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500274, "totalSize", totalSize, "autoDownload", isAuto and "true" or "false")
end

function LSdkMadFunTrack:UpdateRecord(curSize)
    if not self._updateTotalSize or self._updateTotalSize == 0 then return end
    --1% 20% 50% 100%
    local last = self._lastUpdateRecord

    local rate = math.floor((curSize / self._updateTotalSize) * 100)
    local id = 0
    local newLastRate = 0
    if curSize == self._updateTotalSize then
        id = 500282
        newLastRate = 100
    elseif rate >= 50 then
        id = 500280
        newLastRate = 50
    elseif rate >= 20 then
        id = 500278
        newLastRate = 20
    elseif rate >= 1 then
        id = 500275
        newLastRate = 1
    end
    if last and newLastRate <= last then
        return
    end
    if newLastRate <= 0 then return end
    self._lastUpdateRecord = newLastRate
    local totalSecond = math.floor(Time.RawUnityEngineTime.realtimeSinceStartup - (self._beginUpdateTime or 0))
    gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, id, "totalSize", self._updateTotalSize, "totalSecond", totalSecond, "curSize", curSize)
end

function LSdkMadFunTrack:FinishedUpdate()
    local totalSecond = 0
    if self._beginUpdateTime then
        totalSecond = math.floor(Time.RawUnityEngineTime.realtimeSinceStartup - self._beginUpdateTime)

        if not self._lastUpdateRecord or self._lastUpdateRecord < 100 then
            gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500282, "totalSize", self._updateTotalSize, "totalSecond", totalSecond, "curSize", self._updateTotalSize)
        end
    end
    gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500283, "totalSize", self._updateTotalSize or 0, "totalSecond", totalSecond)
end

function LSdkMadFunTrack:UpdateFailure(fileName, curSize, reason)
    local totalSecond = math.floor(Time.RawUnityEngineTime.realtimeSinceStartup - (self._beginUpdateTime or 0))
    gLSdkImpl:CallMethod(LSdkMethod.SensorsTrack, 500273, "totalSize", self._updateTotalSize or 0, "totalSecond", totalSecond,
            "fileName", fileName, "curSize", curSize, "reason", reason)
end
---@endregion 登陆前数据统计埋点



return LSdkMadFunTrack